  1	import * as React from 'react';
  2	import { IRow, IAction, ThProps, IRowData } from '@patternfly/react-table';
  3	import { kialiStyle } from 'styles/StyleUtils';
  4	import { PFColors } from '../../Pf/PfColors';
  5	import {
  6	  EmptyState,
  7	  EmptyStateBody,
  8	  EmptyStateVariant,
  9	  TooltipPosition,
 10	  EmptyStateHeader
 11	} from '@patternfly/react-core';
 12	import { PFBadge, PFBadges } from 'components/Pf/PfBadges';
 13	import { ROUTE_RULES_TOOLTIP, wizardTooltip } from '../WizardHelp';
 14	import { K8sRouteBackendRef } from '../K8sTrafficShifting';
 15	import { SimpleTable } from 'components/Table/SimpleTable';
 16	
 17	export enum MOVE_TYPE {
 18	  UP,
 19	  DOWN
 20	}
 21	
 22	export type K8sRule = {
 23	  backendRefs: K8sRouteBackendRef[];
 24	  filters: string[];
 25	  matches: string[];
 26	};
 27	
 28	type K8sRuleProps = {
 29	  k8sRules: K8sRule[];
 30	  onMoveRule: (index: number, move: MOVE_TYPE) => void;
 31	  onRemoveRule: (index: number) => void;
 32	};
 33	
 34	const validationStyle = kialiStyle({
 35	  marginTop: '0.75rem',
 36	  color: PFColors.Red100
 37	});
 38	
 39	const noRulesStyle = kialiStyle({
 40	  marginTop: '0.75rem',
 41	  color: PFColors.Red100,
 42	  textAlign: 'center',
 43	  width: '100%'
 44	});
 45	
 46	export const K8sRules: React.FC<K8sRuleProps> = (props: K8sRuleProps) => {
 47	  const matchAllIndex = (k8sRules: K8sRule[]): number => {
 48	    let matchAll = -1;
 49	
 50	    for (let index = 0; index < k8sRules.length; index++) {
 51	      const rule = k8sRules[index];
 52	
 53	      if (!rule.matches || rule.matches.length === 0) {
 54	        matchAll = index;
 55	        break;
 56	      }
 57	    }
 58	
 59	    return matchAll;
 60	  };
 61	
 62	  const actionResolver = (_rowData: IRowData, rowIndex: number): IAction[] => {
 63	    const removeAction = {
 64	      title: 'Remove Rule',
 65	      onClick: () => props.onRemoveRule(rowIndex)
 66	    };
 67	
 68	    const moveUpAction = {
 69	      title: 'Move Up',
 70	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.UP)
 71	    };
 72	
 73	    const moveDownAction = {
 74	      title: 'Move Down',
 75	      onClick: () => props.onMoveRule(rowIndex, MOVE_TYPE.DOWN)
 76	    };
 77	
 78	    const actions: IAction[] = [];
 79	
 80	    if (props.k8sRules.length > 0) {
 81	      actions.push(removeAction);
 82	    }
 83	
 84	    if (rowIndex > 0) {
 85	      actions.push(moveUpAction);
 86	    }
 87	
 88	    if (rowIndex + 1 < props.k8sRules.length) {
 89	      actions.push(moveDownAction);
 90	    }
 91	
 92	    return actions;
 93	  };
 94	
 95	  const columns: ThProps[] = [
 96	    {
 97	      title: 'Rule order',
 98	      width: 10
 99	    },
100	    {
101	      title: 'Request Matching'
102	    },
103	    {
104	      title: 'Route Filtering'
105	    },
106	    {
107	      title: 'Route To'
108	    }
109	  ];
110	
111	  let isValid = true;
112	
113	  const matchAll: number = matchAllIndex(props.k8sRules);
114	
115	  const noK8sRules: React.ReactNode = (
116	    <EmptyState variant={EmptyStateVariant.full}>
117	      <EmptyStateHeader titleText="No K8s Route Rules defined" headingLevel="h5" />
118	      <EmptyStateBody className={noRulesStyle}>A Request Routing scenario needs at least a Route Rule</EmptyStateBody>
119	    </EmptyState>
120	  );
121	
122	  const routeRules: IRow[] = props.k8sRules.map((rule, order) => {
123	    isValid = matchAll === -1 || order <= matchAll;
124	
125	    return {
126	      cells: [
127	        <>{order + 1}</>,
128	        <>
129	          {!rule.matches || rule.matches.length === 0
130	            ? 'Any request'
131	            : rule.matches.map((match, i) => <div key={`match_${i}`}>{match}</div>)}
132	          {!isValid && (
133	            <div className={validationStyle}>
134	              Match 'Any request' is defined in a previous rule.
135	              <br />
136	              This rule is not accessible.
137	            </div>
138	          )}
139	        </>,
140	        <>
141	          {!rule.filters || rule.filters.length === 0
142	            ? 'No Request Filter'
143	            : rule.filters.map((filter, i) => <div key={`filter_${i}`}>{filter}</div>)}
144	        </>,
145	        <div key={`br_${order}`}>
146	          {rule.backendRefs &&
147	            rule.backendRefs.map((bRef, i) => {
148	              return (
149	                <div key={`br_${order}_${bRef.name}_${i}`}>
150	                  <PFBadge badge={PFBadges.Service} position={TooltipPosition.top} />
151	                  {bRef.name} ({bRef.weight}% routed traffic)
152	                </div>
153	              );
154	            })}
155	        </div>
156	      ]
157	    };
158	  });
159	
160	  return (
161	    <>
162	      <div>
163	        <span>Route K8sRules</span>
164	        {wizardTooltip(ROUTE_RULES_TOOLTIP)}
165	      </div>
166	
167	      <SimpleTable
168	        label="K8sRules Created"
169	        columns={columns}
170	        rows={routeRules}
171	        actionResolver={actionResolver}
172	        emptyState={noK8sRules}
173	        verticalAlign="middle"
174	      />
175	    </>
176	  );
177	};

